package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.util.Base64
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat

class AuthPrefs(context: Context) {
    private val prefs: SharedPreferences =
        context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)

    companion object {
        private const val KEY_AUTHENTICATED = "authenticated"
        private const val KEY_PASSWORD = "password_hash"
    }

    fun isAuthenticated(): Boolean = prefs.getBoolean(KEY_AUTHENTICATED, false)

    fun setAuthenticated(value: Boolean) {
        prefs.edit().putBoolean(KEY_AUTHENTICATED, value).apply()
    }

    fun savePassword(password: String) {
        prefs.edit().putString(KEY_PASSWORD, password.encodeToBase64()).apply()
    }

    fun hasPassword(): Boolean = !prefs.getString(KEY_PASSWORD, null).isNullOrEmpty()

    fun verifyPassword(password: String): Boolean {
        val stored = prefs.getString(KEY_PASSWORD, null) ?: return false
        return stored == password.encodeToBase64()
    }

    fun clearAuthFlag() {
        prefs.edit().putBoolean(KEY_AUTHENTICATED, false).apply()
    }

    private fun String.encodeToBase64(): String =
        Base64.encodeToString(toByteArray(Charsets.UTF_8), Base64.NO_WRAP)
}

class LoginActivity : AppCompatActivity() {

    private lateinit var authPrefs: AuthPrefs
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    private lateinit var passwordInput: EditText
    private lateinit var loginButton: Button
    private lateinit var useBiometricButton: Button

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        authPrefs = AuthPrefs(this)

        if (authPrefs.isAuthenticated()) {
            navigateToHome()
            return
        }

        passwordInput = findViewById(R.id.passwordInput)
        loginButton = findViewById(R.id.loginButton)
        useBiometricButton = findViewById(R.id.useBiometricButton)

        setupBiometricPrompt()

        loginButton.setOnClickListener {
            val password = passwordInput.text?.toString().orEmpty()
            if (password.isBlank()) {
                Toast.makeText(this, "Please enter your password", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            if (!authPrefs.hasPassword()) {
                authPrefs.savePassword(password)
                authPrefs.setAuthenticated(true)
                Toast.makeText(this, "Password saved. You're signed in.", Toast.LENGTH_SHORT).show()
                navigateToHome()
                return@setOnClickListener
            }

            if (authPrefs.verifyPassword(password)) {
                authPrefs.setAuthenticated(true)
                Toast.makeText(this, "Login successful", Toast.LENGTH_SHORT).show()
                navigateToHome()
            } else {
                Toast.makeText(this, "Incorrect password", Toast.LENGTH_SHORT).show()
            }
        }

        useBiometricButton.setOnClickListener {
            showBiometricPrompt()
        }

        if (isBiometricAvailable()) {
            showBiometricPrompt()
        }
    }

    private fun setupBiometricPrompt() {
        val executor = ContextCompat.getMainExecutor(this)
        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Toast.makeText(
                        this@LoginActivity,
                        "Biometric error: $errString. Please use password.",
                        Toast.LENGTH_SHORT
                    ).show()
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    authPrefs.setAuthenticated(true)
                    Toast.makeText(
                        this@LoginActivity,
                        "Authentication successful",
                        Toast.LENGTH_SHORT
                    ).show()
                    navigateToHome()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(
                        this@LoginActivity,
                        "Biometric not recognized. Please try again or use password.",
                        Toast.LENGTH_SHORT
                    ).show()
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Sign in with fingerprint")
            .setSubtitle("Use your fingerprint for quick access")
            .setNegativeButtonText("Use password")
            .build()
    }

    private fun showBiometricPrompt() {
        if (isBiometricAvailable()) {
            biometricPrompt.authenticate(promptInfo)
        } else {
            Toast.makeText(
                this,
                "Biometric not available. Please sign in with password.",
                Toast.LENGTH_SHORT
            ).show()
        }
    }

    private fun isBiometricAvailable(): Boolean {
        val biometricManager = BiometricManager.from(this)
        return biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG) ==
            BiometricManager.BIOMETRIC_SUCCESS
    }

    private fun navigateToHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }
}

class HomeActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_home)
    }

    override fun onResume() {
        super.onResume()
        val authPrefs = AuthPrefs(this)
        if (!authPrefs.isAuthenticated()) {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }
}